mapper.select:
SELECT id, email, password, oauth_provider, oauth_subject, nickname, profile_image_url, birthdate,
       terms_agreed_at, privacy_agreed_at, marketing_agreed_at, personal_invite_code, is_anonymized, created_at
FROM users
WHERE oauth_provider = #{oauthProvider}
  AND oauth_subject = #{oauthSubject}

SELECT EXISTS(
    SELECT 1
    FROM users
    WHERE personal_invite_code = #{personalInviteCode}
)

